head.b:skin:
/* ============================================================
   NUESTRA VEREDA — Blogger Theme
   Periodismo narrativo y literatura de no ficción · Guayaquil
   ============================================================ */

/* ─── CSS Variables ─────────────────────────────────────────── */
:root {
  --color-cream:        #F4EFE6;
  --color-cream-alt:    #EDE6D8;
  --color-ink:          #1A1612;
  --color-ink-mid:      #3D3530;
  --color-muted:        #6B6058;
  --color-ochre:        #C8943A;
  --color-ochre-light:  #E4B96A;
  --color-mangrove:     #192B21;
  --color-mangrove-mid: #243D2E;
  --color-teal:         #2D6A4F;
  --color-border:       #D0C8BB;
  --color-white:        #FFFFFF;
  --font-display: 'Playfair Display', Georgia, serif;
  --font-body:    'EB Garamond', Georgia, serif;
  --font-ui:      'Jost', 'Helvetica Neue', sans-serif;
}

/* ─── Base reset ────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }
html { scroll-behavior: smooth; }

body {
  margin: 0;
  background-color: var(--color-cream);
  color: var(--color-ink);
  font-family: var(--font-body);
  font-size: 18px;
  line-height: 1.7;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ─── Blogger widget resets ────────────────────────────────── */
.region { margin: 0; padding: 0; }
.widget { margin: 0 !important; padding: 0 !important; border: none !important; }
.widget .widget-title,
.widget h2.title,
.widget-title-wrap { display: none !important; }
.blog-posts { margin: 0; padding: 0; }
.post { margin: 0; padding: 0; }
/* Blogger's default body padding */
#outer-wrapper, #content-wrapper, #main-wrapper { padding: 0 !important; margin: 0 !important; width: 100% !important; }

/* ─── Genre badges ──────────────────────────────────────────── */
.genre-badge {
  display: inline-block;
  font-family: var(--font-ui);
  font-size: 0.65rem;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  padding: 0.2em 0.7em;
  border-radius: 2px;
}
.genre-badge--cronica    { background: #C8943A20; color: #9A6C1E; border: 1px solid #C8943A60; }
.genre-badge--perfil     { background: #2D6A4F20; color: #1E5038; border: 1px solid #2D6A4F60; }
.genre-badge--ensayo     { background: #5A3E5520; color: #42293E; border: 1px solid #5A3E5560; }
.genre-badge--memoria    { background: #7A3B2820; color: #5C2B1A; border: 1px solid #7A3B2860; }
.genre-badge--reportaje  { background: #1A4A6820; color: #123550; border: 1px solid #1A4A6860; }
.genre-badge--testimonio { background: #4A4A3520; color: #323220; border: 1px solid #4A4A3560; }
.genre-badge--default    { background: #1A161220; color: #3D3530; border: 1px solid #1A161240; }
.genre-badge--light {
  background: rgba(255,255,255,0.15);
  color: rgba(255,255,255,0.95);
  border: 1px solid rgba(255,255,255,0.35);
}
/* show only first label badge */
.post-labels .genre-badge-wrap:not(:first-child) { display: none; }

/* ─── Top accent bar ────────────────────────────────────────── */
.top-bar {
  background: var(--color-mangrove);
  color: rgba(255,255,255,0.7);
  font-family: var(--font-ui);
  font-size: 0.72rem;
  font-weight: 400;
  letter-spacing: 0.05em;
  padding: 0.4rem 2rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

/* ─── Masthead ──────────────────────────────────────────────── */
.masthead {
  background: var(--color-cream);
  text-align: center;
  padding: 2.5rem 2rem 0;
  position: relative;
}
.masthead__eyebrow {
  font-family: var(--font-ui);
  font-size: 0.68rem;
  font-weight: 400;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--color-muted);
  margin-bottom: 0.75rem;
}
.masthead__title {
  font-family: var(--font-display);
  font-size: clamp(3.5rem, 8vw, 7rem);
  font-weight: 900;
  line-height: 1;
  letter-spacing: -0.02em;
  color: var(--color-ink);
  margin: 0;
}
.masthead__subtitle {
  font-family: var(--font-body);
  font-size: 1rem;
  font-style: italic;
  color: var(--color-muted);
  margin: 0.75rem 0 0;
}
.masthead__rule {
  height: 1px;
  background: linear-gradient(to right, transparent, var(--color-border), var(--color-ochre), var(--color-border), transparent);
  margin: 1.5rem auto 0;
  max-width: 800px;
}

/* ─── Navigation ────────────────────────────────────────────── */
.nav-bar {
  background: var(--color-cream);
  border-bottom: 1px solid var(--color-border);
  position: sticky;
  top: 0;
  z-index: 50;
  backdrop-filter: blur(8px);
}
.nav-bar__inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 2rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 52px;
}
.nav-bar__logo {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.1rem;
  color: var(--color-ink);
  text-decoration: none;
  letter-spacing: -0.01em;
}
.nav-bar__links {
  display: flex;
  align-items: center;
  gap: 2.5rem;
  list-style: none;
  margin: 0;
  padding: 0;
}
.nav-bar__link {
  font-family: var(--font-ui);
  font-size: 0.8rem;
  font-weight: 500;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--color-ink-mid);
  text-decoration: none;
  transition: color 0.2s ease;
  position: relative;
}
.nav-bar__link::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  right: 0;
  height: 1px;
  background: var(--color-ochre);
  transform: scaleX(0);
  transition: transform 0.25s ease;
}
.nav-bar__link:hover { color: var(--color-ink); }
.nav-bar__link:hover::after { transform: scaleX(1); }

.nav-menu-btn {
  display: none;
  background: none;
  border: none;
  cursor: pointer;
  color: var(--color-ink);
  padding: 0.25rem;
}

/* ─── Hero Carousel ─────────────────────────────────────────── */
.carousel {
  position: relative;
  width: 100%;
  height: clamp(480px, 72vh, 700px);
  overflow: hidden;
  background: var(--color-mangrove);
}
.carousel__slides {
  position: relative;
  width: 100%;
  height: 100%;
}
.carousel__slide {
  position: absolute;
  inset: 0;
  opacity: 0;
  transition: opacity 0.9s cubic-bezier(0.4, 0, 0.2, 1);
  pointer-events: none;
  overflow: hidden;
}
.carousel__slide.is-active {
  opacity: 1;
  pointer-events: auto;
}
.carousel__image {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transform: scale(1.05);
  transition: transform 8s ease;
}
.carousel__slide.is-active .carousel__image { transform: scale(1); }
.carousel__overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to top,
    rgba(15,24,18,0.92) 0%,
    rgba(15,24,18,0.55) 45%,
    rgba(15,24,18,0.15) 100%
  );
}
.carousel__content {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 3rem 4rem;
  max-width: 820px;
}
.carousel__title {
  font-family: var(--font-display);
  font-size: clamp(1.8rem, 4vw, 3rem);
  font-weight: 700;
  line-height: 1.15;
  color: #F8F3EB;
  margin: 0.75rem 0 0.8rem;
}
.carousel__excerpt {
  font-family: var(--font-body);
  font-size: 1.05rem;
  font-style: italic;
  line-height: 1.6;
  color: rgba(248,243,235,0.8);
  margin: 0 0 1.5rem;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.carousel__read-more {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-ui);
  font-size: 0.78rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-ochre-light);
  text-decoration: none;
  border: 1px solid rgba(228,185,106,0.5);
  padding: 0.6rem 1.4rem;
  transition: background 0.25s ease, color 0.25s ease, border-color 0.25s ease;
}
.carousel__read-more:hover {
  background: var(--color-ochre);
  color: var(--color-mangrove);
  border-color: var(--color-ochre);
}
.carousel__nav {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  z-index: 10;
}
.carousel__nav--left  { left: 1.5rem; }
.carousel__nav--right { right: 1.5rem; }
.carousel__nav-btn {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.2);
  color: rgba(255,255,255,0.85);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: background 0.2s, border-color 0.2s;
  backdrop-filter: blur(4px);
}
.carousel__nav-btn:hover {
  background: rgba(255,255,255,0.2);
  border-color: rgba(255,255,255,0.4);
}
.carousel__dots {
  position: absolute;
  bottom: 1.5rem;
  right: 4rem;
  display: flex;
  gap: 0.4rem;
  z-index: 10;
}
.carousel__dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: rgba(255,255,255,0.35);
  border: none;
  cursor: pointer;
  padding: 0;
  transition: background 0.2s, transform 0.2s;
}
.carousel__dot.is-active {
  background: var(--color-ochre-light);
  transform: scale(1.3);
}

/* ─── Section headings ──────────────────────────────────────── */
.section-heading {
  font-family: var(--font-display);
  font-size: clamp(1.6rem, 3vw, 2.2rem);
  font-weight: 700;
  color: var(--color-ink);
  margin: 0 0 0.25rem;
}
.section-rule {
  width: 48px;
  height: 2px;
  background: var(--color-ochre);
  margin: 0.75rem 0 2rem;
}

/* ─── Post grid ─────────────────────────────────────────────── */
.posts-section {
  background: var(--color-cream);
  padding: 5rem 2rem;
}
.posts-section__inner {
  max-width: 1200px;
  margin: 0 auto;
}
.posts-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 2rem;
}
@media (max-width: 900px) { .posts-grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 600px) { .posts-grid { grid-template-columns: 1fr; } }
.posts-grid__item:first-child { grid-column: span 2; }
@media (max-width: 900px) { .posts-grid__item:first-child { grid-column: span 1; } }

.post-card {
  background: var(--color-white);
  display: flex;
  flex-direction: column;
  text-decoration: none;
  color: inherit;
  overflow: hidden;
  border: 1px solid var(--color-border);
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}
.post-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 12px 40px rgba(26,22,18,0.12);
}
.post-card__image-wrap {
  position: relative;
  overflow: hidden;
  aspect-ratio: 16 / 9;
  background: var(--color-mangrove);
}
.posts-grid__item:first-child .post-card__image-wrap { aspect-ratio: 21 / 9; }
.post-card__image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.5s ease;
}
.post-card:hover .post-card__image { transform: scale(1.04); }
.post-card__badge-wrap {
  position: absolute;
  top: 0.75rem;
  left: 0.75rem;
}
.post-card__body {
  padding: 1.4rem 1.6rem 1.8rem;
  display: flex;
  flex-direction: column;
  flex: 1;
}
.post-card__meta {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 0.7rem;
}
.post-card__date {
  font-family: var(--font-ui);
  font-size: 0.7rem;
  color: var(--color-muted);
  letter-spacing: 0.05em;
}
.post-card__title {
  font-family: var(--font-display);
  font-size: 1.15rem;
  font-weight: 700;
  line-height: 1.3;
  color: var(--color-ink);
  margin: 0 0 0.6rem;
}
.posts-grid__item:first-child .post-card__title { font-size: 1.5rem; }
.post-card__excerpt {
  font-family: var(--font-body);
  font-size: 0.95rem;
  color: var(--color-muted);
  line-height: 1.6;
  margin: 0;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  flex: 1;
}
.post-card__author {
  font-family: var(--font-ui);
  font-size: 0.72rem;
  color: var(--color-muted);
  margin-top: 1rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--color-border);
}
.archive-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-ui);
  font-size: 0.78rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-white);
  background: var(--color-ink);
  padding: 0.85rem 2rem;
  text-decoration: none;
  transition: background 0.25s ease;
  border: none;
  cursor: pointer;
}
.archive-btn:hover { background: var(--color-mangrove); }

/* ─── Individual post body ──────────────────────────────────── */
.post-body h1,
.post-body h2,
.post-body h3,
.post-body h4 {
  font-family: var(--font-display);
  color: var(--color-ink);
  line-height: 1.3;
  margin: 2rem 0 0.75rem;
}
.post-body h2 { font-size: 1.6rem; }
.post-body h3 { font-size: 1.3rem; }
.post-body p { margin: 0 0 1.4rem; }
.post-body a { color: var(--color-teal); }
.post-body a:hover { color: var(--color-ochre); }
.post-body blockquote {
  margin: 2rem 0;
  padding: 1rem 1.5rem;
  border-left: 3px solid var(--color-ochre);
  font-style: italic;
  color: var(--color-ink-mid);
  background: var(--color-cream-alt);
}
.post-body img {
  max-width: 100%;
  height: auto;
  display: block;
  margin: 2rem auto;
}

/* ─── Contact section ───────────────────────────────────────── */
.contact-section {
  background: var(--color-mangrove);
  padding: 6rem 2rem;
  position: relative;
  overflow: hidden;
}
.contact-section::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 2px;
  background: linear-gradient(to right, transparent, var(--color-ochre), transparent);
}
.contact-section__inner {
  max-width: 1100px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 1fr 1.4fr;
  gap: 5rem;
  align-items: start;
}
@media (max-width: 800px) {
  .contact-section__inner { grid-template-columns: 1fr; gap: 3rem; }
}
.contact-info__heading {
  font-family: var(--font-display);
  font-size: 2rem;
  font-weight: 700;
  color: #F8F3EB;
  margin: 0 0 0.5rem;
}
.contact-info__lead {
  font-family: var(--font-body);
  font-style: italic;
  font-size: 1rem;
  color: rgba(248,243,235,0.65);
  margin: 0 0 2.5rem;
  line-height: 1.6;
}
.contact-info__item {
  display: flex;
  align-items: flex-start;
  gap: 0.75rem;
  margin-bottom: 1.25rem;
}
.contact-info__icon {
  width: 18px;
  height: 18px;
  color: var(--color-ochre-light);
  flex-shrink: 0;
  margin-top: 2px;
}
.contact-info__label {
  font-family: var(--font-ui);
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--color-ochre-light);
  margin-bottom: 0.15rem;
  display: block;
}
.contact-info__value {
  font-family: var(--font-body);
  font-size: 0.95rem;
  color: rgba(248,243,235,0.8);
}
.social-links {
  display: flex;
  gap: 1rem;
  margin-top: 2rem;
}
.social-link {
  width: 38px;
  height: 38px;
  border: 1px solid rgba(255,255,255,0.2);
  color: rgba(255,255,255,0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  transition: border-color 0.2s, color 0.2s, background 0.2s;
}
.social-link:hover {
  border-color: var(--color-ochre);
  color: var(--color-ochre-light);
  background: rgba(200,148,58,0.1);
}

/* ─── Contact form ──────────────────────────────────────────── */
.contact-form {
  display: flex;
  flex-direction: column;
  gap: 1.2rem;
}
.form-field { display: flex; flex-direction: column; gap: 0.35rem; }
.form-label {
  font-family: var(--font-ui);
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: rgba(255,255,255,0.5);
}
.form-input,
.form-textarea {
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.12);
  color: rgba(248,243,235,0.9);
  font-family: var(--font-body);
  font-size: 1rem;
  padding: 0.75rem 1rem;
  outline: none;
  transition: border-color 0.2s, background 0.2s;
  border-radius: 0;
  width: 100%;
}
.form-input::placeholder,
.form-textarea::placeholder { color: rgba(255,255,255,0.25); }
.form-input:focus,
.form-textarea:focus {
  border-color: rgba(228,185,106,0.5);
  background: rgba(255,255,255,0.08);
}
.form-textarea { min-height: 140px; resize: vertical; }
.form-submit {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  font-family: var(--font-ui);
  font-size: 0.78rem;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  background: var(--color-ochre);
  color: var(--color-mangrove);
  border: none;
  padding: 0.9rem 2rem;
  cursor: pointer;
  transition: background 0.25s ease;
  align-self: flex-start;
}
.form-submit:hover { background: var(--color-ochre-light); }
.form-note {
  font-family: var(--font-ui);
  font-size: 0.7rem;
  color: rgba(255,255,255,0.3);
  margin-top: 0.5rem;
}

/* ─── Footer ────────────────────────────────────────────────── */
.site-footer {
  background: #0F1C14;
  padding: 3.5rem 2rem 2rem;
  color: rgba(255,255,255,0.5);
}
.site-footer__inner {
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  grid-template-columns: 2fr 1fr 1fr;
  gap: 3rem;
  padding-bottom: 2.5rem;
  border-bottom: 1px solid rgba(255,255,255,0.08);
  margin-bottom: 2rem;
}
@media (max-width: 700px) {
  .site-footer__inner { grid-template-columns: 1fr; gap: 2rem; }
}
.footer-brand__name {
  font-family: var(--font-display);
  font-size: 1.5rem;
  font-weight: 700;
  color: #F8F3EB;
  margin: 0 0 0.5rem;
}
.footer-brand__desc {
  font-family: var(--font-body);
  font-style: italic;
  font-size: 0.9rem;
  color: rgba(255,255,255,0.4);
  line-height: 1.6;
  max-width: 300px;
}
.footer-col__heading {
  font-family: var(--font-ui);
  font-size: 0.65rem;
  font-weight: 600;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--color-ochre-light);
  margin-bottom: 1rem;
}
.footer-links {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.footer-links a {
  font-family: var(--font-ui);
  font-size: 0.82rem;
  color: rgba(255,255,255,0.45);
  text-decoration: none;
  transition: color 0.2s;
}
.footer-links a:hover { color: rgba(255,255,255,0.8); }
.footer-social {
  display: flex;
  gap: 0.75rem;
  margin-top: 0.5rem;
}
.footer-social-link {
  width: 34px;
  height: 34px;
  border: 1px solid rgba(255,255,255,0.12);
  color: rgba(255,255,255,0.4);
  display: flex;
  align-items: center;
  justify-content: center;
  text-decoration: none;
  transition: border-color 0.2s, color 0.2s;
}
.footer-social-link:hover {
  border-color: rgba(228,185,106,0.5);
  color: var(--color-ochre-light);
}
.footer-bottom {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 0.5rem;
}
.footer-copyright {
  font-family: var(--font-ui);
  font-size: 0.72rem;
  color: rgba(255,255,255,0.28);
  letter-spacing: 0.04em;
}

/* ─── Pagination ────────────────────────────────────────────── */
.pagination-wrap {
  display: flex;
  justify-content: center;
  gap: 1rem;
  margin-top: 3.5rem;
}

/* ─── Animations ────────────────────────────────────────────── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}
.animate-fade-up { animation: fadeUp 0.7s ease both; }

/* ─── Responsive ────────────────────────────────────────────── */
@media (max-width: 700px) {
  .top-bar { display: none; }
  .masthead__title { font-size: 3rem; }
  .carousel__content { padding: 2rem 1.5rem; }
  .posts-section { padding: 3rem 1.25rem; }
  .nav-bar__links { gap: 1.25rem; }
  .nav-bar__inner { padding: 0 1.25rem; }
  .carousel__nav-btn { width: 36px; height: 36px; }
  .carousel__nav--left  { left: 0.75rem; }
  .carousel__nav--right { right: 0.75rem; }
  .carousel__dots { right: 1.5rem; }
}
@media (max-width: 600px) {
  .nav-menu-btn { display: flex; }
  .nav-bar__links { display: none; }
  .nav-bar__links.is-open {
    display: flex;
    flex-direction: column;
    position: absolute;
    top: 52px;
    left: 0;
    right: 0;
    background: var(--color-cream);
    border-bottom: 1px solid var(--color-border);
    padding: 1rem 1.5rem;
    gap: 1.25rem;
    z-index: 100;
  }
}

body.script:
//

/* ── Genre badge class mapping ─────────────────────────── */
var GENRE_MAP = {
  'Crónica':        'genre-badge--cronica',
  'Cronica':        'genre-badge--cronica',
  'Perfil':         'genre-badge--perfil',
  'Ensayo':         'genre-badge--ensayo',
  'Memoria urbana': 'genre-badge--memoria',
  'Reportaje':      'genre-badge--reportaje',
  'Testimonio':     'genre-badge--testimonio'
};

/* ── Navigation toggle (mobile) ───────────────────────── */
function toggleNav() {
  var links = document.getElementById('nav-links');
  var btn   = document.getElementById('nav-toggle');
  if (!links) return;
  var open = links.classList.toggle('is-open');
  if (btn) {
    btn.innerHTML = open
      ? '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>'
      : '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg>';
  }
}

/* ── Genre badge class assignment ────────────────────── */
function applyGenreBadges() {
  document.querySelectorAll('[data-genre]').forEach(function(el) {
    var genre = el.getAttribute('data-genre') || '';
    var cls   = GENRE_MAP[genre] || 'genre-badge--default';
    if (!el.classList.contains(cls)) el.classList.add(cls);
  });
}

/* ── Thumbnail URL upscaling ──────────────────────────── */
function upscaleThumbnails() {
  var selectors = ['.post-card__image', '.post-hero-img'];
  selectors.forEach(function(sel) {
    document.querySelectorAll(sel).forEach(function(img) {
      var src = img.getAttribute('src') || '';
      if (!src) return;
      /* Blogger thumbnail: .../s72-c/... → .../w1200/...  */
      var large = src
        .replace(/=s\d+-c($|\&)/, '=w1200-h675-c')
        .replace(/\/s\d+-c\//, '/w1200/')
        .replace(/\/s\d+\//, '/w1200/');
      if (large !== src) img.src = large;
    });
  });
}

/* ── Carousel state ───────────────────────────────────── */
var _posts    = [];
var _active   = 0;
var _timer    = null;
var _paused   = false;

function _esc(s) {
  if (!s) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function _fmtDate(iso) {
  try {
    return new Date(iso).toLocaleDateString('es-EC', { year: 'numeric', month: 'long', day: 'numeric' });
  } catch(e) { return ''; }
}

function _goTo(idx) {
  var slides = document.querySelectorAll('.carousel__slide');
  var dots   = document.querySelectorAll('.carousel__dot');
  if (slides[_active]) {
    slides[_active].classList.remove('is-active');
    slides[_active].setAttribute('aria-hidden', 'true');
  }
  if (dots[_active]) {
    dots[_active].classList.remove('is-active');
    dots[_active].setAttribute('aria-selected', 'false');
  }
  _active = ((idx % _posts.length) + _posts.length) % _posts.length;
  if (slides[_active]) {
    slides[_active].classList.add('is-active');
    slides[_active].setAttribute('aria-hidden', 'false');
  }
  if (dots[_active]) {
    dots[_active].classList.add('is-active');
    dots[_active].setAttribute('aria-selected', 'true');
  }
}

function carouselNext() { _goTo(_active + 1); }
function carouselPrev() { _goTo(_active - 1); }

function _buildCarousel(posts) {
  _posts  = posts || [];
  _active = 0;
  var slidesEl = document.getElementById('carousel-slides');
  var dotsEl   = document.getElementById('carousel-dots');
  var carousel = document.getElementById('hero-carousel');
  if (!slidesEl || !carousel) return;

  if (!_posts.length) { carousel.style.display = 'none'; return; }

  slidesEl.innerHTML = '';
  if (dotsEl) dotsEl.innerHTML = '';

  _posts.forEach(function(post, i) {
    var imgUrl  = post.thumb || '';
    var genre   = post.labels && post.labels[0] ? post.labels[0] : '';
    var arrowSvg = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>';

    var slide = document.createElement('div');
    slide.className  = 'carousel__slide' + (i === 0 ? ' is-active' : '');
    slide.setAttribute('aria-hidden', i !== 0 ? 'true' : 'false');
    slide.innerHTML  = (imgUrl
      ? '<img class="carousel__image" src="' + _esc(imgUrl) + '" alt="" loading="' + (i === 0 ? 'eager' : 'lazy') + '"/>'
      : '<div class="carousel__image" style="background:var(--color-mangrove-mid);"></div>'
    ) + '<div class="carousel__overlay"></div>'
      + '<div class="carousel__content">'
      + '<span class="genre-badge genre-badge--light" data-genre="' + _esc(genre) + '">' + _esc(genre) + '</span>'
      + '<h2 class="carousel__title">' + _esc(post.title) + '</h2>'
      + '<p class="carousel__excerpt">' + _esc(post.summary) + '</p>'
      + '<div style="display:flex;align-items:center;gap:1.5rem;flex-wrap:wrap;">'
      + '<a href="' + _esc(post.url) + '" class="carousel__read-more">Leer más ' + arrowSvg + '</a>'
      + '<span style="font-family:var(--font-ui);font-size:0.72rem;color:rgba(255,255,255,0.45);letter-spacing:0.04em;">'
      + _esc(post.author) + ' · ' + _esc(post.dateStr)
      + '</span></div></div>';
    slidesEl.appendChild(slide);

    if (dotsEl) {
      var dot = document.createElement('button');
      dot.className = 'carousel__dot' + (i === 0 ? ' is-active' : '');
      dot.setAttribute('aria-label', 'Ir a la diapositiva ' + (i + 1));
      dot.setAttribute('role', 'tab');
      dot.setAttribute('aria-selected', i === 0 ? 'true' : 'false');
      (function(idx) {
        dot.addEventListener('click', function() { _goTo(idx); });
      })(i);
      dotsEl.appendChild(dot);
    }
  });

  if (_posts.length > 1) {
    _timer = setInterval(function() { if (!_paused) carouselNext(); }, 6000);
  }
  carousel.addEventListener('mouseenter', function() { _paused = true; });
  carousel.addEventListener('mouseleave', function() { _paused = false; });

  applyGenreBadges();
}

function _parseEntries(entries) {
  return entries.map(function(e) {
    var url = '';
    (e.link || []).forEach(function(l) { if (l.rel === 'alternate') url = l.href; });
    var thumb = '';
    if (e['media$thumbnail'] && e['media$thumbnail'].url) {
      thumb = e['media$thumbnail'].url
        .replace(/=s\d+-c($|\&)/, '=w1200-h675-c')
        .replace(/\/s\d+-c\//, '/w1200/')
        .replace(/\/s\d+\//, '/w1200/');
    }
    var labels = (e.category || []).map(function(c) { return c.term; })
      .filter(function(t) { return t !== 'Destacado'; });
    return {
      title:   e.title   ? e.title['$t']   : '',
      summary: e.summary ? e.summary['$t'] : '',
      url:     url,
      thumb:   thumb,
      dateStr: e.published ? _fmtDate(e.published['$t']) : '',
      author:  e.author && e.author[0] ? e.author[0].name['$t'] : '',
      labels:  labels
    };
  });
}

/* ── Load carousel posts from Blogger feed API ─────────── */
function loadCarousel() {
  var featured = '/feeds/posts/default/-/Destacado?alt=json&max-results=5';
  var fallback  = '/feeds/posts/default?alt=json&max-results=5';

  fetch(featured)
    .then(function(r) { return r.ok ? r.json() : Promise.reject(); })
    .then(function(d) {
      var entries = (d.feed && d.feed.entry) ? d.feed.entry : [];
      if (!entries.length) return fetch(fallback).then(function(r) { return r.json(); })
        .then(function(d2) { return (d2.feed && d2.feed.entry) ? d2.feed.entry : []; });
      return entries;
    })
    .then(function(entries) { _buildCarousel(_parseEntries(entries)); })
    .catch(function() {
      var el = document.getElementById('hero-carousel');
      if (el) el.style.display = 'none';
    });
}

/* ── Footer year ───────────────────────────────────────── */
function setFooterYear() {
  var el = document.getElementById('footer-year');
  if (el) el.textContent = new Date().getFullYear();
}

/* ── Init ─────────────────────────────────────────────── */
document.addEventListener('DOMContentLoaded', function() {
  applyGenreBadges();
  upscaleThumbnails();
  setFooterYear();
  if (document.getElementById('hero-carousel')) loadCarousel();
});

//
